<?php namespace App\Repositories\Inventory;use App\Repositories\BaseRepository;use App\Models\Inventory\Item;use Illuminate\Database\Eloquent\Collection;class ItemRepository extends BaseRepository{    public function __construct(Item $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Item    {        return $this->query()->where('name', $name)->first();    }    public function findByCode(string $code): ?Item    {        return $this->query()->where('code', $code)->first();    }    public function findByCategory(int $categoryId): Collection    {        return $this->findByField('category_id', $categoryId);    }    public function getActiveItems(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getLowStockItems(int $threshold = 10): Collection    {        return $this->query()->where('stock_quantity', '<=', $threshold)->where('is_active', true)->get();    }    public function getOutOfStockItems(): Collection    {        return $this->query()->where('stock_quantity', '<=', 0)->get();    }    public function searchItems(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getByUnit(string $unit): Collection    {        return $this->findByField('unit', $unit);    }    public function adjustStock(int $id, int $quantity): bool    {        $item = $this->getById($id);        $newStock = $item->stock_quantity + $quantity;        return $this->update($id, ['stock_quantity' => max(0, $newStock)]);    }    public function getItemsBelowReorderLevel(): Collection    {        return $this->query()->where('stock_quantity', '<=', 'reorder_level')->where('is_active', true)->get();    }}